content:
功能背景现有一个域名管理系统，需要上传申请原件（图片）到数据库，现在是将图片以二进制形式直接存储到数据库中。在执行修改操作时，后端返回给前端的为base64格式的照片，如果没有修改原件，重新上传后端使用MultipartFile就无法接收成功。所以需要将base64格式的照片重新转成file格式。
base64直接转file这种方式可能存在兼容性问题。
//将base64转换为文件
    dataURLtoFile: function(data, filename) &#123; 
	    var arr = data.split(','),
	        mime = arr[0].match(/:(.*?);/)[1],
	        bstr = atob(arr[1]),
	        n = bstr.length,
	        u8arr = new Uint8Array(n);
	    while (n--) &#123;
	        u8arr[n] = bstr.charCodeAt(n);
	    &#125;
	    return new File([u8arr], filename, &#123; type: mime &#125;);
	&#125;,
    //调用
    var file = dataURLtoFile(base64Data, imgName);



base64转成bolb，blob再转成file格式这种方式可以解决兼容性问题。
//将base64转换为blob
baseToBlob: function(data) &#123; 
    var arr = data.split(','),
        mime = arr[0].match(/:(.*?);/)[1],
        bstr = atob(arr[1]),
        n = bstr.length,
        u8arr = new Uint8Array(n);
    while (n--) &#123;
        u8arr[n] = bstr.charCodeAt(n);
    &#125;
    return new Blob([u8arr], &#123; type: mime &#125;);
&#125;,
//将blob转换为file
blobToFile: function(blob, fileName)&#123;
   blob.lastModifiedDate = new Date();
   blob.name = fileName;
   return blob;
&#125;,
//调用
var blob = baseToBlob(base64Data);
var file = blobToFile(blob, imgName);
